={"model": "qwen2.5:3b", "prompt": "Eres un experto en compras. Analiza esta solicitud y extrae los datos.

SOLICITUD:
Descripcion: {{ $json.descripcion }}
Cantidad: {{ $json.cantidad_requerida }}
Producto ID: {{ $json.stock_bajo_producto_id }}

Extrae estos campos y responde SOLO JSON sin markdown:
{"producto_nombre": "...", "cantidad": 0, "urgencia": "alta|media|baja", "comentarios": "..."}", "stream": false, "options": {"temperature": 0.1}}

parameters.jsCode:
const text = $json.response;
const prev = $('Edit Fields').first().json;

let jsonText = text;
if (text.includes('```json')) {
  jsonText = text.split('```json')[1].split('```')[0];
} else if (text.includes('{')) {
  jsonText = text.substring(text.indexOf('{'), text.lastIndexOf('}') + 1);
}

try {
  const parsed = JSON.parse(jsonText.trim());
  return [{ json: { ...prev, ...parsed } }];
} catch (e) {
  return [{ json: { ...prev, producto_nombre: 'Desconocido', cantidad: parseInt(prev.cantidad_requerida) || 1, urgencia: 'media', comentarios: '' } }];
}

