parameters.jsCode:
const text = $json.response;
const prev = $('Code Parse 3').first().json;

let jsonText = text;
if (text.includes('```json')) {
  jsonText = text.split('```json')[1].split('```')[0];
} else if (text.includes('{')) {
  jsonText = text.substring(text.indexOf('{'), text.lastIndexOf('}') + 1);
}

try {
  const parsed = JSON.parse(jsonText.trim());
  if (!parsed.proveedor_id && prev.proveedor_recomendado) {
    parsed.proveedor_id = prev.proveedor_recomendado;
  }
  if (!parsed.solicitud_id && prev.solicitud_id) {
    parsed.solicitud_id = prev.solicitud_id;
  }
  return [{ json: { ...prev, ...parsed } }];
} catch (e) {
  return [{ json: {
    solicitud_id: prev.solicitud_id,
    proveedor_id: prev.proveedor_recomendado || 1,
    cantidad: prev.cantidad || 1,
    notas: 'Generado automaticamente',
    prioridad: 'normal'
  } }];
}
